I'll help you create a normalized schema for your log data. Here's the modified main.ts that creates appropriate tables and handles the NDJSON import:

```typescript
import { Database } from "@db/sqlite";

// Create tables with proper schema
function initializeDatabase(db: Database) {
  // Main logs table
  db.prepare(`
    CREATE TABLE IF NOT EXISTS logs (
      dt TEXT PRIMARY KEY,
      _app TEXT,
      _source_id TEXT,
      file TEXT,
      platform TEXT,
      kubernetes_container_id TEXT,
      kubernetes_container_name TEXT,
      kubernetes_namespace TEXT,
      kubernetes_pod_name TEXT,
      kubernetes_pod_ip TEXT
    )
  `).run();

  // Messages table (normalized from the message field)
  db.prepare(`
    CREATE TABLE IF NOT EXISTS log_messages (
      dt TEXT PRIMARY KEY,
      asctime TEXT,
      body TEXT,
      client_ip TEXT,
      client_user TEXT,
      correlation_id TEXT,
      created REAL,
      filename TEXT,
      funcName TEXT,
      levelname TEXT,
      levelno INTEGER,
      lineno INTEGER,
      message TEXT,
      method TEXT,
      module TEXT,
      msecs REAL,
      name TEXT,
      pathname TEXT,
      process INTEGER,
      processName TEXT,
      relativeCreated REAL,
      thread REAL,
      threadName TEXT,
      uri TEXT,
      FOREIGN KEY(dt) REFERENCES logs(dt)
    )
  `).run();

  // Create indexes for common query patterns
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_logs_dt ON logs(dt)`).run();
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_messages_client_user ON log_messages(client_user)`).run();
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_messages_uri ON log_messages(uri)`).run();
}

function insertLog(db: Database, logEntry: any) {
  const insertLogStmt = db.prepare(`
    INSERT OR IGNORE INTO logs (
      dt, _app, _source_id, file, platform,
      kubernetes_container_id, kubernetes_container_name,
      kubernetes_namespace, kubernetes_pod_name, kubernetes_pod_ip
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);

  const insertMessageStmt = db.prepare(`
    INSERT OR IGNORE INTO log_messages (
      dt, asctime, body, client_ip, client_user,
      correlation_id, created, filename, funcName,
      levelname, levelno, lineno, message, method,
      module, msecs, name, pathname, process,
      processName, relativeCreated, thread,
      threadName, uri
    ) VALUES (
      ?, ?, ?, ?, ?, ?, ?, ?, ?, ?,
      ?, ?, ?, ?, ?, ?, ?, ?, ?,
      ?, ?, ?, ?, ?
    )
  `);

  // Insert into logs table
  insertLogStmt.run(
    logEntry.dt,
    logEntry._app,
    logEntry._source_id,
    logEntry.file,
    logEntry.platform,
    logEntry.kubernetes?.container_id,
    logEntry.kubernetes?.container_name,
    logEntry.kubernetes?.pod_namespace,
    logEntry.kubernetes?.pod_name,
    logEntry.kubernetes?.pod_ip
  );

  // Insert into log_messages table
  if (logEntry.message) {
    insertMessageStmt.run(
      logEntry.dt,
      logEntry.message.asctime,
      logEntry.message.body,
      logEntry.message.client_ip,
      logEntry.message.client_user,
      logEntry.message.correlation_id,
      logEntry.message.created,
      logEntry.message.filename,
      logEntry.message.funcName,
      logEntry.message.levelname,
      logEntry.message.levelno,
      logEntry.message.lineno,
      logEntry.message.message,
      logEntry.message.method,
      logEntry.message.module,
      logEntry.message.msecs,
      logEntry.message.name,
      logEntry.message.pathname,
      logEntry.message.process,
      logEntry.message.processName,
      logEntry.message.relativeCreated,
      logEntry.message.thread,
      logEntry.message.threadName,
      logEntry.message.uri
    );
  }
}

async function parseAndInsertLogs(filePath: string, db: Database) {
  const file = await Deno.open(filePath);
  const decoder = new TextDecoder();
  const lines = decoder.decode(await Deno.readAll(file)).split('\n');

  db.prepare('BEGIN TRANSACTION').run();

  for (const line of lines) {
    if (line.trim()) {
      try {
        const logEntry = JSON.parse(line);
        insertLog(db, logEntry);
      } catch (e) {
        console.error('Error parsing line:', e);
      }
    }
  }

  db.prepare('COMMIT').run();
  file.close();
}

if (import.meta.main) {
  const db = new Database("logs.db");

  // Initialize database schema
  initializeDatabase(db);

  // Parse and insert logs
  await parseAndInsertLogs("./combined/all-raw.ndjson", db);

  // Example query: Get all logs for a specific user in a date range
  const rows = db.prepare(`
    SELECT 
      l.dt,
      m.client_user,
      m.uri,
      m.message
    FROM logs l
    JOIN log_messages m ON l.dt = m.dt
    WHERE m.client_user = ?
    AND l.dt BETWEEN ? AND ?
    ORDER BY l.dt
  `).all('oandria@otovo.com', '2024-11-19T00:00:00Z', '2024-11-19T23:59:59Z');

  console.log('Query results:', rows);

  db.close();
}
```

This implementation:

1. Creates two main tables:
   - `logs`: Contains the main log entry data
   - `log_messages`: Contains the normalized message data

2. Uses the `dt` field as the primary key in both tables to handle duplicates (INSERT OR IGNORE)

3. Creates appropriate indexes for common query patterns

4. Processes the NDJSON file line by line and inserts the data into both tables

5. Uses transactions for better insert performance

6. Includes an example query showing how to query the data

To use this:

1. Make sure your database driver (@db/sqlite) is properly imported
2. Run the script with your NDJSON file path
3. The script will create a SQLite database with your log data

You can then query the data using SQL, with proper date filtering and joins between the tables. The schema supports both timestamp-based queries and full-text searches on various fields.

Example queries you might want to run:

```sql
-- Get all requests from a specific user
SELECT dt, uri, message 
FROM log_messages 
WHERE client_user = ? 
ORDER BY dt;

-- Get request counts by user in a time range
SELECT client_user, COUNT(*) as request_count 
FROM log_messages 
WHERE dt BETWEEN ? AND ? 
GROUP BY client_user 
ORDER BY request_count DESC;

-- Get all errors
SELECT l.dt, m.message, m.levelname 
FROM logs l 
JOIN log_messages m ON l.dt = m.dt 
WHERE m.levelname = 'ERROR';
```
