Ah, you're right! Let's simplify the schema and properly handle the date fields. Here's the revised version:

```typescript
import { Database } from "@db/sqlite";

function initializeDatabase(db: Database) {
  // Main logs table with just essential fields
  db.prepare(`
    CREATE TABLE IF NOT EXISTS logs (
      dt DATETIME PRIMARY KEY,
      asctime DATETIME,
      body TEXT,
      client_ip TEXT,
      client_user TEXT,
      correlation_id TEXT,
      created REAL,
      filename TEXT,
      funcName TEXT,
      levelname TEXT,
      levelno INTEGER,
      lineno INTEGER,
      message TEXT,
      method TEXT,
      module TEXT,
      msecs REAL,
      name TEXT,
      pathname TEXT,
      process INTEGER,
      processName TEXT,
      relativeCreated REAL,
      thread REAL,
      threadName TEXT,
      uri TEXT
    )
  `).run();

  // Create indexes for common query patterns
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_logs_dt ON logs(dt)`).run();
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_logs_asctime ON logs(asctime)`).run();
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_logs_client_user ON logs(client_user)`).run();
  db.prepare(`CREATE INDEX IF NOT EXISTS idx_logs_uri ON logs(uri)`).run();
}

function insertLog(db: Database, logEntry: any) {
  const insertStmt = db.prepare(`
    INSERT OR IGNORE INTO logs (
      dt, asctime, body, client_ip, client_user,
      correlation_id, created, filename, funcName,
      levelname, levelno, lineno, message, method,
      module, msecs, name, pathname, process,
      processName, relativeCreated, thread,
      threadName, uri
    ) VALUES (
      datetime(?), datetime(?), ?, ?, ?, 
      ?, ?, ?, ?, ?,
      ?, ?, ?, ?, ?,
      ?, ?, ?, ?,
      ?, ?, ?, ?, ?
    )
  `);

  // Insert log entry
  insertStmt.run(
    logEntry.dt,
    logEntry.message.asctime,
    logEntry.message.body,
    logEntry.message.client_ip,
    logEntry.message.client_user,
    logEntry.message.correlation_id,
    logEntry.message.created,
    logEntry.message.filename,
    logEntry.message.funcName,
    logEntry.message.levelname,
    logEntry.message.levelno,
    logEntry.message.lineno,
    logEntry.message.message,
    logEntry.message.method,
    logEntry.message.module,
    logEntry.message.msecs,
    logEntry.message.name,
    logEntry.message.pathname,
    logEntry.message.process,
    logEntry.message.processName,
    logEntry.message.relativeCreated,
    logEntry.message.thread,
    logEntry.message.threadName,
    logEntry.message.uri
  );
}

async function parseAndInsertLogs(filePath: string, db: Database) {
  const file = await Deno.open(filePath);
  const decoder = new TextDecoder();
  const lines = decoder.decode(await Deno.readAll(file)).split('\n');

  db.prepare('BEGIN TRANSACTION').run();

  for (const line of lines) {
    if (line.trim()) {
      try {
        const logEntry = JSON.parse(line);
        insertLog(db, logEntry);
      } catch (e) {
        console.error('Error parsing line:', e);
      }
    }
  }

  db.prepare('COMMIT').run();
  file.close();
}

if (import.meta.main) {
  const db = new Database("logs.db");

  // Initialize database schema
  initializeDatabase(db);

  // Parse and insert logs
  await parseAndInsertLogs("./combined/all-raw.ndjson", db);

  // Example query: Get all logs for a specific user in a date range
  const rows = db.prepare(`
    SELECT 
      datetime(dt) as datetime,
      client_user,
      uri,
      message
    FROM logs
    WHERE client_user = ?
    AND dt BETWEEN datetime(?) AND datetime(?)
    ORDER BY dt
  `).all('oandria@otovo.com', '2024-11-19 00:00:00', '2024-11-19 23:59:59');

  console.log('Query results:', rows);

  db.close();
}
```

Now the schema:
1. Only includes the fields from the `message` object plus the main `dt` timestamp
2. Uses proper `DATETIME` types for both `dt` and `asctime` fields
3. Uses SQLite's `datetime()` function for proper date handling
4. Still maintains indexes for common query patterns

Example queries you can now run:

```sql
-- Get requests per hour
SELECT 
    strftime('%Y-%m-%d %H:00:00', dt) as hour,
    COUNT(*) as request_count
FROM logs
GROUP BY hour
ORDER BY hour;

-- Get all requests from a specific user on a specific day
SELECT 
    datetime(dt) as timestamp,
    uri,
    message
FROM logs
WHERE client_user = ?
AND date(dt) = date('2024-11-19')
ORDER BY dt;

-- Get requests per user per day
SELECT 
    date(dt) as day,
    client_user,
    COUNT(*) as request_count
FROM logs
GROUP BY day, client_user
ORDER BY day DESC, request_count DESC;
```

This schema will make it much easier to work with the timestamps and perform date-based analysis of the log data.
